delegation_log = []

def capture_step(step_output):
    tool_name = getattr(step_output, "tool", None)
    if tool_name and "delegate" in tool_name.lower():
        delegation_log.append({
            "tool": tool_name,
            "input": str(getattr(step_output, "tool_input", "")),
            "result": str(getattr(step_output, "result", ""))[:200],
        })

crew = Crew(
    agents=[lead, specialist],
    tasks=[task],
    step_callback=capture_step,
)
result = crew.kickoff()

print(f"Delegation events: {len(delegation_log)}")
for event in delegation_log:
    print(f"  {event['tool']}: {event['input'][:80]}")
